import { useEffect, useState } from 'react';
import { ShoppingCart, User } from "lucide-react";
import logo from "../assets/logo-edit.svg";

<img src={logo} alt="Ila Cafe Logo" className="h-20" />
 // update if path differs

export default function Navbar() {
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <header
  className={`fixed top-0 left-0 w-full z-50 transition-all duration-300 ${
    isScrolled ? 'bg-cafebeige shadow-md' : 'bg-transparent'
  } flex items-center justify-between px-6 py-6 min-h-[80px]`}
>
      {/* Left: Menu */}
      <nav className="flex gap-6 text-sm font-medium text-gray-700 items-center">
        <a
          href="#"
          className="bg-textbrown text-white px-4 py-2 rounded-md text-sm font-semibold hover:bg-amber-700 transition"
        >
          Menu
        </a>
        <a href="#" className="hover:text-amber-600">About</a>
        <a href="#" className="hover:text-amber-600">Contact</a>
      </nav>

      {/* Center: Logo */}
      <div className="absolute left-1/2 transform -translate-x-1/2">
        <img src={logo} alt="Ila Cafe Logo" className="h-20 w-auto" />
      </div>

      {/* Right: Icons */}
      <div className="flex gap-4 text-gray-700">
        <button className="hover:text-amber-600">
          <ShoppingCart size={22} />
        </button>
        <button className="hover:text-amber-600">
          <User size={22} />
        </button>
      </div>
    </header>
  );
}
